   730→/**
   731→ * Notes List Component
   732→ */
   733→const NotesList: React.FC<{
   734→  activeTags: string[];
   735→  onOpenTemplateLibrary: () => void;
   736→  onOpenExportModal: () => void;
   737→}> = ({ activeTags, onOpenTemplateLibrary, onOpenExportModal }) => {
   738→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   739→  // Get raw notes and store config (stable references)
   740→  const notesObj = useNotesStore((state) => state.notes);
   741→  const sortConfig = useNotesStore((state) => state.sortConfig);
   742→  const filter = useNotesStore((state) => state.filter);
   743→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   744→  const createNote = useNotesStore((state) => state.createNote);
   745→  const bulkAddTag = useNotesStore((state) => state.bulkAddTag);
   746→  const bulkRemoveTag = useNotesStore((state) => state.bulkRemoveTag);
   747→
   748→  // Bulk operations state
   749→  const [selectionMode, setSelectionMode] = useState(false);
   750→  const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());
   751→  const [bulkTagDialogOpen, setBulkTagDialogOpen] = useState(false);
   752→  const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
   753→  const [bulkTagValue, setBulkTagValue] = useState('');
   754→
   755→  // Bulk operations handlers
   756→  const toggleSelectionMode = () => {
   757→    setSelectionMode(!selectionMode);
   758→    if (selectionMode) {
   759→      setSelectedNoteIds(new Set());
   760→    }
   761→  };
   762→
   763→  const toggleNoteSelection = (noteId: string) => {
   764→    setSelectedNoteIds((prev) => {
   765→      const next = new Set(prev);
   766→      if (next.has(noteId)) {
   767→        next.delete(noteId);
   768→      } else {
   769→        next.add(noteId);
   770→      }
   771→      return next;
   772→    });
   773→  };
   774→
   775→  const selectAll = () => {
   776→    const allIds = notes.map((n) => n.id);
   777→    setSelectedNoteIds(new Set(allIds));
   778→  };
   779→
   780→  const deselectAll = () => {
   781→    setSelectedNoteIds(new Set());
   782→  };
   783→
   784→  const handleBulkAddTag = () => {
   785→    setBulkTagAction('add');
   786→    setBulkTagDialogOpen(true);
   787→  };
   788→
   789→  const handleBulkRemoveTag = () => {
   790→    setBulkTagAction('remove');
   791→    setBulkTagDialogOpen(true);
   792→  };
   793→
   794→  const confirmBulkTagAction = (value: string) => {
   795→    if (!value.trim() || selectedNoteIds.size === 0) return;
   796→
   797→    if (bulkTagAction === 'add') {
   798→      bulkAddTag(Array.from(selectedNoteIds), value.trim());
   799→    } else if (bulkTagAction === 'remove') {
   800→      bulkRemoveTag(Array.from(selectedNoteIds), value.trim());
   801→    }
   802→
   803→    // Clear selection and close dialog
   804→    setBulkTagDialogOpen(false);
   805→    setBulkTagValue('');
   806→    setSelectedNoteIds(new Set());
   807→    setSelectionMode(false);
   808→  };
   809→
   810→  // Compute filtered/sorted notes with useMemo
   811→  const notes = useMemo(() => {
   812→    // Filter by folder
   813→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   814→    let filtered = activeFolderId === null
   815→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   816→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   817→
   818→    // Filter by tags (AND logic - note must have ALL selected tags or their children)
   819→    if (activeTags.length > 0) {
   820→      filtered = filtered.filter((note) =>
   821→        activeTags.every((filterTag) =>
   822→          note.tags.some((noteTag) => tagMatchesFilter(noteTag, filterTag))
   823→        )
   824→      );
   825→    }
   826→
   827→    // Apply filter (archived, pinned, favorites, etc.)
   828→    switch (filter) {
   829→      case 'favorites':
   830→        filtered = filtered.filter((note) => note.isFavorite);
   831→        break;
   832→      case 'pinned':
   833→        filtered = filtered.filter((note) => note.isPinned);
   834→        break;
   835→      case 'archived':
   836→        filtered = filtered.filter((note) => note.isArchived);
   837→        break;
   838→      case 'unarchived':
   839→        filtered = filtered.filter((note) => !note.isArchived);
   840→        break;
   841→    }
   842→
   843→    // Sort notes
   844→    const sorted = [...filtered].sort((a, b) => {
   845→      let comparison = 0;
   846→      switch (sortConfig.field) {
   847→        case 'title':
   848→          comparison = a.title.localeCompare(b.title);
   849→          break;
   850→        case 'createdAt':
   851→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   852→          break;
   853→        case 'updatedAt':
   854→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   855→          break;
   856→      }
   857→      return sortConfig.order === 'asc' ? comparison : -comparison;
   858→    });
   859→
   860→    // Always pin pinned notes to top
   861→    return sorted.sort((a, b) => {
   862→      if (a.isPinned && !b.isPinned) return -1;
   863→      if (!a.isPinned && b.isPinned) return 1;
   864→      return 0;
   865→    });
   866→  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);
   867→
   868→  return (
   869→    <div className="flex-1 overflow-y-auto">
   870→      <div className="bento-card p-4 m-3">
   871→        {/* Notes header */}
   872→        <div className="flex items-center justify-between mb-4">
   873→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   874→            Notes ({notes.length})
   875→          </h3>
   876→          <div className="flex items-center gap-2">
   877→            <button
   878→              onClick={onOpenExportModal}
   879→              className="px-3 py-1.5 rounded-lg text-sm font-medium border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-200 flex items-center gap-1"
   880→              title="Export notes (Cmd+Shift+E)"
   881→            >
   882→              <FileDown className="w-4 h-4" />
   883→              Export
   884→            </button>
   885→            <button
   886→              onClick={toggleSelectionMode}
   887→              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
   888→                selectionMode
   889→                  ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   890→                  : 'border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   891→              }`}
   892→            >
   893→              {selectionMode ? 'Cancel Selection' : 'Select Notes'}
   894→            </button>
   895→            <button
   896→              onClick={onOpenTemplateLibrary}
   897→              className="px-3 py-1.5 bg-accent-purple text-white rounded-lg hover:bg-accent-purple-hover transition-all duration-200 text-sm font-medium flex items-center gap-1"
   898→              title="Create note from template"
   899→            >
   900→              <Sparkles className="w-4 h-4" />
   901→              From Template
   902→            </button>
   903→            <button
   904→              onClick={() => createNote({ folderId: activeFolderId })}
   905→              className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   906→            >
   907→              + New Note
   908→            </button>
   909→          </div>
   910→        </div>
   911→
   912→        {/* Bulk Operations Toolbar */}
   913→        {selectionMode && selectedNoteIds.size > 0 && (
   914→          <div className="mb-4 p-3 rounded-lg bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/30">
   915→            <div className="flex items-center justify-between">
   916→              <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   917→                {selectedNoteIds.size} note{selectedNoteIds.size !== 1 ? 's' : ''} selected
   918→              </span>
   919→              <div className="flex items-center gap-2">
   920→                <button
   921→                  onClick={selectAll}
   922→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   923→                >
   924→                  Select All
   925→                </button>
   926→                <button
   927→                  onClick={deselectAll}
   928→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   929→                >
   930→                  Deselect All
   931→                </button>
   932→                <button
   933→                  onClick={handleBulkAddTag}
   934→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-blue text-white hover:bg-accent-blue-hover transition-colors"
   935→                >
   936→                  Add Tag
   937→                </button>
   938→                <button
   939→                  onClick={handleBulkRemoveTag}
   940→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-red/20 text-accent-red hover:bg-accent-red/30 transition-colors"
   941→                >
   942→                  Remove Tag
   943→                </button>
   944→              </div>
   945→            </div>
   946→          </div>
   947→        )}
   948→
   949→      {/* Notes list */}
   950→      <div className="space-y-3">
   951→        {notes.map((note) => (
   952→          <NoteListItem
   953→            key={note.id}
   954→            note={note}
   955→            isActive={note.id === activeNoteId}
   956→            isSelectionMode={selectionMode}
   957→            isSelected={selectedNoteIds.has(note.id)}
   958→            onToggleSelection={toggleNoteSelection}
   959→          />
   960→        ))}
   961→      </div>
   962→
   963→      {/* Empty state */}
   964→      {notes.length === 0 && (
   965→        <div className="text-center py-16 animate-fade-in">
   966→          <div className="flex justify-center mb-6">
   967→            <div className="p-6 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-2xl">
   968→              <FileText className="w-16 h-16 text-accent-cyan dark:text-accent-magenta" />
   969→            </div>
   970→          </div>
   971→          <h3 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-3">
   972→            {activeTags.length > 0 ? 'No notes match these tags' : 'No notes in this folder'}
   973→          </h3>
   974→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2 max-w-sm mx-auto">
   975→            {activeTags.length > 0
   976→              ? 'Try removing some tags or create a new note'
   977→              : 'Start capturing your thoughts, ideas, and knowledge'}
   978→          </p>
   979→          <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary mb-6">
   980→            Tip: Use <kbd className="px-2 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-xs font-mono">Cmd+N</kbd> to create notes quickly
   981→          </p>
   982→          <button
