/**
 * Notes Page
 *
 * Phase 5: Updated with TabNavigation for 3 tabs:
 * - Notes (main view with 3-column layout)
 * - Daily Notes (daily notes calendar)
 * - Graph (knowledge graph view)
 *
 * Main notes interface with 3-column layout:
 * - Left: Folder tree + Notes list
 * - Center: Rich text editor
 * - Right: Note metadata (optional, collapsible)
 */

import React, { useEffect, useState, useRef, useMemo, lazy, Suspense } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
  ChevronDown,
  ChevronRight,
  FolderOpen,
  Folder,
  FileText,
  Edit2,
  Trash2,
  Pin,
  Star,
  Tag,
  Check,
  Download,
  Loader2,
  FileDown,
  Sparkles,
  Calendar as CalendarIcon,
  Network,
} from 'lucide-react';
import { useNotesStore } from '../stores/useNotesStore';
import { useFoldersStore } from '../stores/useFoldersStore';
import { NotesEditor, NotesEditorEmpty } from '../widgets/NotesEditor';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { PromptDialog } from '../components/PromptDialog';
import { useUndoStore } from '../stores/useUndoStore';
import { exportNoteToMarkdown } from '../services/noteExport';
import { exportNoteToPDF } from '../services/notePdfExport';
import { logger } from '../services/logger';
import type { Note } from '../types/notes';
import { DailyNotesCalendar } from '../components/DailyNotesCalendar';
import { useSettingsStore } from '../stores/useSettingsStore';
import { TagFilter } from '../components/TagFilter';
import { TagManager } from '../components/TagManager';
import { tagMatchesFilter } from '../utils/tagHierarchy';
import { TemplateLibrary } from '../components/TemplateLibrary';
import { substituteTemplateVariables, extractTemplateVariables } from '../utils/templateVariables';
import type { NoteTemplate } from '../types/notes';
import { ExportNotesModal } from '../components/ExportNotesModal';
import { PageContent } from '../components/PageContent';
import { TabNavigation, type Tab } from '../components/TabNavigation';

// Lazy load GraphView for code splitting
const GraphView = lazy(() => import('./GraphView'));

// Phase 5: Tab configuration for Notes page
type NotesTabType = 'notes' | 'daily' | 'graph';

const VALID_TABS: NotesTabType[] = ['notes', 'daily', 'graph'];

// Tab configuration for TabNavigation component
const NOTES_TABS: Tab[] = [
  { id: 'notes', label: 'Notes', icon: FileText },
  { id: 'daily', label: 'Daily Notes', icon: CalendarIcon },
  { id: 'graph', label: 'Graph', icon: Network },
];

// Loading fallback for GraphView
const GraphViewLoader = () => (
  <div className="flex items-center justify-center min-h-[400px]">
    <div className="text-center">
      <div className="inline-block h-12 w-12 animate-spin rounded-full border-4 border-solid border-accent-cyan border-r-transparent" />
      <p className="mt-4 text-sm text-text-light-secondary dark:text-text-dark-secondary">Loading Graph...</p>
    </div>
  </div>
);

const log = logger.module('Notes');

/**
 * Recursive Folder Tree Node Component
 */
interface FolderTreeNodeProps {
  node: any;
  depth: number;
  activeFolderId: string | null;
  expandedFolderIds: Set<string>;
  onSelect: (id: string) => void;
  onToggleExpanded: (id: string) => void;
  onDelete: (id: string, name: string) => void;
  onRename: (id: string, name: string) => void;
  getFolderNoteCount: (id: string) => number;
}

const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
  node,
  depth,
  activeFolderId,
  expandedFolderIds,
  onSelect,
  onToggleExpanded,
  onDelete,
  onRename,
  getFolderNoteCount,
}) => {
  const isExpanded = expandedFolderIds.has(node.id);
  const hasChildren = node.children && node.children.length > 0;
  const noteCount = getFolderNoteCount(node.id);

  return (
    <div>
      <div
        className={`group relative rounded-lg transition-all duration-standard ${
          activeFolderId === node.id
            ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10'
            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated hover:shadow-sm'
        }`}
        style={{ paddingLeft: `${depth * 16}px` }}
      >
        <div className="flex items-center">
          {/* Expand/collapse button */}
          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation();
                onToggleExpanded(node.id);
              }}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
            >
              {isExpanded ? (
                <ChevronDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
              ) : (
                <ChevronRight className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
              )}
            </button>
          )}
          {!hasChildren && <span className="w-6" />}

          {/* Folder button */}
          <button
            onClick={() => onSelect(node.id)}
            className={`flex-1 text-left px-3 py-2 transition-all duration-standard flex items-center gap-2 ${
              activeFolderId === node.id
                ? 'text-accent-cyan dark:text-accent-magenta font-medium'
                : 'text-text-light-secondary dark:text-text-dark-secondary group-hover:text-text-light-primary dark:group-hover:text-text-dark-primary'
            }`}
          >
            {hasChildren ? (
              isExpanded ? (
                <FolderOpen className="w-4 h-4" />
              ) : (
                <Folder className="w-4 h-4" />
              )
            ) : (
              <FileText className="w-4 h-4" />
            )}
            <span>{node.name}</span>
            {noteCount > 0 && (
              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                ({noteCount})
              </span>
            )}
          </button>

          {/* Action buttons */}
          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
            <button
              onClick={(e) => {
                e.stopPropagation();
                onRename(node.id, node.name);
              }}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
              title="Rename folder"
              aria-label="Rename folder"
            >
              <Edit2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
            </button>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDelete(node.id, node.name);
              }}
              className="p-1 hover:bg-accent-red/10 dark:hover:bg-accent-red/20 rounded text-accent-red transition-colors"
              title="Delete folder"
              aria-label="Delete folder"
            >
              <Trash2 className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Children */}
      {isExpanded && hasChildren && (
        <div className="ml-4">
          {node.children.map((child: any) => (
            <FolderTreeNode
              key={child.id}
              node={child}
              depth={depth + 1}
              activeFolderId={activeFolderId}
              expandedFolderIds={expandedFolderIds}
              onSelect={onSelect}
              onToggleExpanded={onToggleExpanded}
              onDelete={onDelete}
              onRename={onRename}
              getFolderNoteCount={getFolderNoteCount}
            />
          ))}
        </div>
      )}
    </div>
  );
};

/**
 * Folder Sidebar Component (Simplified for MVP)
 */
const FolderSidebar: React.FC<{
  activeTags: string[];
  onAddTag: (tag: string) => void;
  onRemoveTag: (tag: string) => void;
  onClearAllTags: () => void;
  onOpenTagManager: () => void;
}> = ({ activeTags, onAddTag, onRemoveTag, onClearAllTags, onOpenTagManager }) => {
  // Get raw folders object (stable reference unless folders change)
  const foldersObj = useFoldersStore((state) => state.folders);
  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
  const createFolder = useFoldersStore((state) => state.createFolder);
  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
  const updateFolder = useFoldersStore((state) => state.updateFolder);
  const notesObj = useNotesStore((state) => state.notes);
  const searchNotes = useNotesStore((state) => state.searchNotes);

  // Dialog state
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [selectedFolderName, setSelectedFolderName] = useState('');

  // Search state
  const [searchQuery, setSearchQuery] = useState('');
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Keyboard shortcut for search (Cmd+K)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        searchInputRef.current?.focus();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Get tree structure for nested folders
  const getTree = useFoldersStore((state) => state.getTree);
  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);

  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);

  // Get note count for a folder
  const getFolderNoteCount = (folderId: string) => {
    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
  };

  // Handle folder deletion
  const handleDeleteFolder = (folderId: string, folderName: string) => {
    setSelectedFolderId(folderId);
    setSelectedFolderName(folderName);
    setDeleteDialogOpen(true);
  };

  const confirmDeleteFolder = () => {
    if (!selectedFolderId) return;

    // Save folder and notes for undo
    const folderToDelete = foldersObj[selectedFolderId];
    if (!folderToDelete) {
      log.warn('Folder not found', { folderId: selectedFolderId });
      return;
    }

    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
    const noteCount = notesToDelete.length;

    // Delete all notes in this folder (without undo since folder undo will handle it)
    // We need to temporarily bypass the undo system for individual notes
    notesToDelete.forEach(note => {
      // Call the store action directly without triggering undo
      useNotesStore.setState((state) => {
        const { [note.id]: deleted, ...remainingNotes } = state.notes;
        return {
          notes: remainingNotes,
          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
        };
      });
    });

    // Delete the folder
    deleteFolder(selectedFolderId);

    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });

    // Add undo action to restore folder AND notes
    useUndoStore.getState().addUndoAction(
      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
      () => {
        // Restore the folder
        useFoldersStore.setState((state) => ({
          folders: {
            ...state.folders,
            [folderToDelete.id]: folderToDelete,
          },
        }));

        // Restore all notes
        useNotesStore.setState((state) => {
          const restoredNotes = { ...state.notes };
          notesToDelete.forEach(note => {
            restoredNotes[note.id] = note;
          });
          return {
            notes: restoredNotes,
          };
        });

        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
      }
    );
  };

  // Handle folder rename
  const handleRenameFolder = (folderId: string, currentName: string) => {
    setSelectedFolderId(folderId);
    setSelectedFolderName(currentName);
    setRenameDialogOpen(true);
  };

  const confirmRenameFolder = (newName: string) => {
    if (!selectedFolderId || !newName.trim()) return;
    updateFolder(selectedFolderId, { name: newName.trim() });
  };

  return (
    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
      {/* Folders header */}
      <div className="flex items-center justify-between mb-4 flex-shrink-0">
        <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">Folders</h3>
        <button
          onClick={() => createFolder()}
          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
          title="New Folder"
        >
          + Folder
        </button>
      </div>

      {/* Search Input */}
      <div className="px-3 py-2">
        <input
          type="text"
          placeholder="Search notes... (Cmd+K)"
          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
                     bg-surface-light dark:bg-surface-dark
                     text-text-light-primary dark:text-text-dark-primary
                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          ref={searchInputRef}
        />
      </div>

      {/* All Notes (root level) */}
      {!searchQuery.trim() && (
        <button
          onClick={() => setActiveFolder(null)}
          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center gap-2 text-base ${
            activeFolderId === null
              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
          }`}
        >
          <FolderOpen className="w-4 h-4" />
          All Notes
        </button>
      )}

      {/* Search Results OR Folder list */}
      {searchQuery.trim() ? (
        /* Search Results */
        <div className="px-3 overflow-y-auto flex-1">
          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
            {searchNotes(searchQuery).length} results for "{searchQuery}"
          </h3>
          <div className="space-y-2">
            {searchNotes(searchQuery).map((note) => (
              <div
                key={note.id}
                onClick={() => {
                  setSearchQuery(''); // Clear search
                  // Note will be selected via the NotesList component
                }}
                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
              >
                <div className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
                  {note.title || 'Untitled'}
                </div>
                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
                  {note.contentText?.slice(0, 150)}...
                </div>
                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                  {new Date(note.updatedAt).toLocaleDateString()}
                </div>
              </div>
            ))}
            {searchNotes(searchQuery).length === 0 && (
              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
                No notes found for "{searchQuery}"
              </div>
            )}
          </div>
        </div>
      ) : (
        /* Folder tree - Scrollable */
        <div className="space-y-1 overflow-y-auto flex-1">
          {folderTree.map((node) => (
            <FolderTreeNode
              key={node.id}
              node={node}
              depth={0}
              activeFolderId={activeFolderId}
              expandedFolderIds={expandedFolderIds}
              onSelect={setActiveFolder}
              onToggleExpanded={toggleExpanded}
              onDelete={handleDeleteFolder}
              onRename={handleRenameFolder}
              getFolderNoteCount={getFolderNoteCount}
            />
          ))}

          {/* Empty state */}
          {folderTree.length === 0 && (
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
              No folders yet
            </div>
          )}
        </div>
      )}

      {/* Tag Filter Section */}
      <div className="px-4 py-3 border-t border-border-light dark:border-border-dark">
        <TagFilter
          activeTags={activeTags}
          onAddTag={onAddTag}
          onRemoveTag={onRemoveTag}
          onClearAll={onClearAllTags}
        />
        <button
          onClick={onOpenTagManager}
          className="w-full mt-3 px-3 py-2 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
        >
          Manage Tags
        </button>
      </div>

      {/* Delete Folder Confirmation Dialog */}
      <ConfirmDialog
        isOpen={deleteDialogOpen}
        onClose={() => setDeleteDialogOpen(false)}
        onConfirm={confirmDeleteFolder}
        title="Delete Folder"
        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
        confirmText="Delete"
        variant="danger"
      />

      {/* Rename Folder Prompt Dialog */}
      <PromptDialog
        isOpen={renameDialogOpen}
        onClose={() => setRenameDialogOpen(false)}
        onConfirm={confirmRenameFolder}
        title="Rename Folder"
        message="Enter a new name for this folder:"
        defaultValue={selectedFolderName}
        placeholder="Folder name"
        confirmText="Rename"
      />
    </div>
  );
};

/**
 * Note List Item Component
 */
const NoteListItem: React.FC<{
  note: Note;
  isActive: boolean;
  isSelectionMode?: boolean;
  isSelected?: boolean;
  onToggleSelection?: (id: string) => void;
}> = ({
  note,
  isActive,
  isSelectionMode = false,
  isSelected = false,
  onToggleSelection,
}) => {
  const setActiveNote = useNotesStore((state) => state.setActiveNote);
  const deleteNote = useNotesStore((state) => state.deleteNote);
  const togglePin = useNotesStore((state) => state.togglePin);
  const toggleFavorite = useNotesStore((state) => state.toggleFavorite);
  const tagColors = useSettingsStore((state) => state.tagColors);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [exportSuccess, setExportSuccess] = useState<string | null>(null);

  // Handle PDF export with loading state
  const handlePDFExport = async (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsExporting(true);
    try {
      await exportNoteToPDF(note, (filename) => {
        setExportSuccess(filename);
        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
      });
    } catch (error) {
      log.error('PDF export failed', { error });
    } finally {
      setIsExporting(false);
    }
  };

  // Format date
  const formatDate = (date: Date) => {
    const now = new Date();
    const diff = now.getTime() - new Date(date).getTime();
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (days === 0) return 'Today';
    if (days === 1) return 'Yesterday';
    if (days < 7) return `${days} days ago`;
    return new Date(date).toLocaleDateString();
  };

  // First line of content
  const preview = note.contentText.split('\n')[0] || 'No content';

  return (
    <div
      className={`group relative p-4 rounded-lg cursor-pointer transition-all duration-standard hover:scale-[1.01] ${
        isActive
          ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10 border-l-4 border-accent-cyan dark:border-accent-magenta shadow-sm'
          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated border-l-4 border-transparent hover:shadow-sm'
      }`}
      onClick={() => setActiveNote(note.id)}
    >
      {/* Export Success Notification */}
      {exportSuccess && (
        <div className="absolute -top-8 left-0 right-0 bg-accent-green text-white text-xs py-1 px-2 rounded shadow-lg z-10 text-center flex items-center justify-center gap-1">
          <Check className="w-3 h-3" />
          Exported: {exportSuccess}
        </div>
      )}

      {/* Main layout: Vertical actions on left + Content on right */}
      <div className="flex items-start gap-2">
        {/* Vertical action column - appears on left side on hover */}
        <div className="flex flex-col gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-200 shrink-0 w-6">
          <button
            onClick={(e) => {
              e.stopPropagation();
              exportNoteToMarkdown(note);
            }}
            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110"
            title="Export to Markdown"
            aria-label="Export to Markdown"
          >
            <Download className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
          </button>
          <button
            onClick={handlePDFExport}
            disabled={isExporting}
            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100"
            title={isExporting ? 'Exporting...' : 'Export to PDF'}
            aria-label={isExporting ? 'Exporting to PDF' : 'Export to PDF'}
          >
            {isExporting ? (
              <Loader2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary animate-spin" />
            ) : (
              <FileDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
            )}
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              toggleFavorite(note.id);
            }}
            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110"
            title={note.isFavorite ? 'Unfavorite' : 'Favorite'}
            aria-label={note.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
          >
            <Star
              className={`w-4 h-4 transition-all duration-200 ${
                note.isFavorite
                  ? 'fill-accent-yellow text-accent-yellow'
                  : 'text-text-light-secondary dark:text-text-dark-secondary'
              }`}
            />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              togglePin(note.id);
            }}
            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-all duration-150 hover:scale-110"
            title={note.isPinned ? 'Unpin' : 'Pin'}
            aria-label={note.isPinned ? 'Unpin note' : 'Pin note'}
          >
            <Pin className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              setShowDeleteDialog(true);
            }}
            className="p-1 hover:bg-accent-red/10 dark:hover:bg-accent-red/20 rounded text-accent-red transition-all duration-150 hover:scale-110"
            title="Delete"
            aria-label="Delete note"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>

        {/* Content area - No truncation needed with vertical actions */}
        <div className="flex-1 min-w-0">
          {/* Title row with static indicators */}
          <div className="flex items-start gap-2 mb-1">
            <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary flex-1">
              {note.title}
            </h4>
            {/* Static indicators: always visible when present */}
            <div className="flex items-center gap-1 shrink-0">
              {note.isFavorite && <Star className="w-4 h-4 fill-accent-yellow text-accent-yellow" />}
              {note.isPinned && <Pin className="w-4 h-4 text-accent-yellow" />}
            </div>
          </div>

          {/* Preview */}
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2 mb-3">
            {preview}
          </p>

          {/* Tags Display */}
          {note.tags.length > 0 && (
            <div className="flex flex-wrap gap-1 mb-2">
              {note.tags.slice(0, 3).map((tag) => {
                const color = tagColors[tag];
                return (
                  <span
                    key={tag}
                    className={`inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium rounded ${
                      color
                        ? `bg-${color}/10 text-${color} dark:bg-${color}/20`
                        : 'bg-accent-purple/10 text-accent-purple dark:bg-accent-cyan/10 dark:text-accent-cyan'
                    }`}
                  >
                    <Tag className="w-3 h-3" />
                    {tag}
                  </span>
                );
              })}
              {note.tags.length > 3 && (
                <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary px-1">
                  +{note.tags.length - 3} more
                </span>
              )}
            </div>
          )}

          {/* Meta */}
          <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
            <span>{formatDate(note.updatedAt)}</span>
          </div>
        </div>

        {/* Selection checkbox (if in selection mode) */}
        {isSelectionMode && onToggleSelection && (
          <div className="shrink-0 ml-2" onClick={(e) => e.stopPropagation()}>
            <input
              type="checkbox"
              checked={isSelected}
              onChange={() => onToggleSelection(note.id)}
              className="w-4 h-4 rounded border-border-light dark:border-border-dark cursor-pointer"
              aria-label={`Select note ${note.title}`}
            />
          </div>
        )}
      </div>

      {/* Delete Confirmation Dialog */}
      {showDeleteDialog && (
        <ConfirmDialog
          isOpen={true}
          onClose={() => setShowDeleteDialog(false)}
          onConfirm={() => {
            deleteNote(note.id);
            setShowDeleteDialog(false);
          }}
          title="Delete Note"
          message={`Are you sure you want to delete "${note.title}"? This action cannot be undone.`}
          variant="danger"
        />
      )}
    </div>
  );
};

/**
 * Notes List Component
 */
const NotesList: React.FC<{
  activeTags: string[];
  onOpenTemplateLibrary: () => void;
  onOpenExportModal: () => void;
}> = ({ activeTags, onOpenTemplateLibrary, onOpenExportModal }) => {
  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
  // Get raw notes and store config (stable references)
  const notesObj = useNotesStore((state) => state.notes);
  const sortConfig = useNotesStore((state) => state.sortConfig);
  const filter = useNotesStore((state) => state.filter);
  const activeNoteId = useNotesStore((state) => state.activeNoteId);
  const createNote = useNotesStore((state) => state.createNote);
  const bulkAddTag = useNotesStore((state) => state.bulkAddTag);
  const bulkRemoveTag = useNotesStore((state) => state.bulkRemoveTag);

  // Bulk operations state
  const [selectionMode, setSelectionMode] = useState(false);
  const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());
  const [bulkTagDialogOpen, setBulkTagDialogOpen] = useState(false);
  const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
  const [bulkTagValue, setBulkTagValue] = useState('');

  // Bulk operations handlers
  const toggleSelectionMode = () => {
    setSelectionMode(!selectionMode);
    if (selectionMode) {
      setSelectedNoteIds(new Set());
    }
  };

  const toggleNoteSelection = (noteId: string) => {
    setSelectedNoteIds((prev) => {
      const next = new Set(prev);
      if (next.has(noteId)) {
        next.delete(noteId);
      } else {
        next.add(noteId);
      }
      return next;
    });
  };

  const selectAll = () => {
    const allIds = notes.map((n) => n.id);
    setSelectedNoteIds(new Set(allIds));
  };

  const deselectAll = () => {
    setSelectedNoteIds(new Set());
  };

  const handleBulkAddTag = () => {
    setBulkTagAction('add');
    setBulkTagDialogOpen(true);
  };

  const handleBulkRemoveTag = () => {
    setBulkTagAction('remove');
    setBulkTagDialogOpen(true);
  };

  const confirmBulkTagAction = (value: string) => {
    if (!value.trim() || selectedNoteIds.size === 0) return;

    if (bulkTagAction === 'add') {
      bulkAddTag(Array.from(selectedNoteIds), value.trim());
    } else if (bulkTagAction === 'remove') {
      bulkRemoveTag(Array.from(selectedNoteIds), value.trim());
    }

    // Clear selection and close dialog
    setBulkTagDialogOpen(false);
    setBulkTagValue('');
    setSelectedNoteIds(new Set());
    setSelectionMode(false);
  };

  // Compute filtered/sorted notes with useMemo
  const notes = useMemo(() => {
    // Filter by folder
    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
    let filtered = activeFolderId === null
      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);

    // Filter by tags (AND logic - note must have ALL selected tags or their children)
    if (activeTags.length > 0) {
      filtered = filtered.filter((note) =>
        activeTags.every((filterTag) =>
          note.tags.some((noteTag) => tagMatchesFilter(noteTag, filterTag))
        )
      );
    }

    // Apply filter (archived, pinned, favorites, etc.)
    switch (filter) {
      case 'favorites':
        filtered = filtered.filter((note) => note.isFavorite);
        break;
      case 'pinned':
        filtered = filtered.filter((note) => note.isPinned);
        break;
      case 'archived':
        filtered = filtered.filter((note) => note.isArchived);
        break;
      case 'unarchived':
        filtered = filtered.filter((note) => !note.isArchived);
        break;
    }

    // Sort notes
    const sorted = [...filtered].sort((a, b) => {
      let comparison = 0;
      switch (sortConfig.field) {
        case 'title':
          comparison = a.title.localeCompare(b.title);
          break;
        case 'createdAt':
          comparison = a.createdAt.getTime() - b.createdAt.getTime();
          break;
        case 'updatedAt':
          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
          break;
      }
      return sortConfig.order === 'asc' ? comparison : -comparison;
    });

    // Always pin pinned notes to top
    return sorted.sort((a, b) => {
      if (a.isPinned && !b.isPinned) return -1;
      if (!a.isPinned && b.isPinned) return 1;
      return 0;
    });
  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);

  return (
    <div className="flex-1 overflow-y-auto">
      <div className="bento-card p-4 m-3">
        {/* Notes header */}
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
            Notes ({notes.length})
          </h3>
          <div className="flex items-center gap-2">
            <button
              onClick={onOpenExportModal}
              className="px-3 py-1.5 rounded-lg text-sm font-medium border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-200 flex items-center gap-1"
              title="Export notes (Cmd+Shift+E)"
            >
              <FileDown className="w-4 h-4" />
              Export
            </button>
            <button
              onClick={toggleSelectionMode}
              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                selectionMode
                  ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
                  : 'border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
              }`}
            >
              {selectionMode ? 'Cancel Selection' : 'Select Notes'}
            </button>
            <button
              onClick={onOpenTemplateLibrary}
              className="px-3 py-1.5 bg-accent-purple text-white rounded-lg hover:bg-accent-purple-hover transition-all duration-200 text-sm font-medium flex items-center gap-1"
              title="Create note from template"
            >
              <Sparkles className="w-4 h-4" />
              From Template
            </button>
            <button
              onClick={() => createNote({ folderId: activeFolderId })}
              className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
            >
              + New Note
            </button>
          </div>
        </div>

        {/* Bulk Operations Toolbar */}
        {selectionMode && selectedNoteIds.size > 0 && (
          <div className="mb-4 p-3 rounded-lg bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/30">
            <div className="flex items-center justify-between">
              <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
                {selectedNoteIds.size} note{selectedNoteIds.size !== 1 ? 's' : ''} selected
              </span>
              <div className="flex items-center gap-2">
                <button
                  onClick={selectAll}
                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
                >
                  Select All
                </button>
                <button
                  onClick={deselectAll}
                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
                >
                  Deselect All
                </button>
                <button
                  onClick={handleBulkAddTag}
                  className="px-3 py-1 text-xs font-medium rounded bg-accent-blue text-white hover:bg-accent-blue-hover transition-colors"
                >
                  Add Tag
                </button>
                <button
                  onClick={handleBulkRemoveTag}
                  className="px-3 py-1 text-xs font-medium rounded bg-accent-red/20 text-accent-red hover:bg-accent-red/30 transition-colors"
                >
                  Remove Tag
                </button>
              </div>
            </div>
          </div>
        )}

      {/* Notes list */}
      <div className="space-y-3">
        {notes.map((note) => (
          <NoteListItem
            key={note.id}
            note={note}
            isActive={note.id === activeNoteId}
            isSelectionMode={selectionMode}
            isSelected={selectedNoteIds.has(note.id)}
            onToggleSelection={toggleNoteSelection}
          />
        ))}
      </div>

      {/* Empty state */}
      {notes.length === 0 && (
        <div className="text-center py-16 animate-fade-in">
          <div className="flex justify-center mb-6">
            <div className="p-6 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-2xl">
              <FileText className="w-16 h-16 text-accent-cyan dark:text-accent-magenta" />
            </div>
          </div>
          <h3 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-3">
            {activeTags.length > 0 ? 'No notes match these tags' : 'No notes in this folder'}
          </h3>
          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2 max-w-sm mx-auto">
            {activeTags.length > 0
              ? 'Try removing some tags or create a new note'
              : 'Start capturing your thoughts, ideas, and knowledge'}
          </p>
          <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary mb-6">
            Tip: Use <kbd className="px-2 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-xs font-mono">Cmd+N</kbd> to create notes quickly
          </p>
          <button
            onClick={() => createNote({ folderId: activeFolderId })}
            className="px-6 py-3 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-standard font-medium inline-flex items-center gap-2"
          >
            <FileText className="w-5 h-5" />
            Create Your First Note
          </button>
        </div>
      )}
      </div>

      {/* Bulk Tag Dialog */}
      {bulkTagDialogOpen && (
        <PromptDialog
          isOpen={true}
          onClose={() => {
            setBulkTagDialogOpen(false);
            setBulkTagValue('');
          }}
          onConfirm={confirmBulkTagAction}
          title={bulkTagAction === 'add' ? 'Add Tag to Selected Notes' : 'Remove Tag from Selected Notes'}
          message={
            bulkTagAction === 'add'
              ? `Enter tag name to add to ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
              : `Enter tag name to remove from ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
          }
          defaultValue={bulkTagValue}
          placeholder="Tag name"
          confirmText={bulkTagAction === 'add' ? 'Add Tag' : 'Remove Tag'}
        />
      )}
    </div>
  );
};

/**
 * Notes Page Component
 * Phase 5: Updated with TabNavigation for tabs (Notes, Daily Notes, Graph)
 */
export const Notes: React.FC = () => {
  const activeNoteId = useNotesStore((state) => state.activeNoteId);
  const getOrCreateDailyNote = useNotesStore((state) => state.getOrCreateDailyNote);
  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [sidebarWidth, setSidebarWidth] = useState(320);
  const [isResizing, setIsResizing] = useState(false);
  const sidebarRef = useRef<HTMLDivElement>(null);
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();
  const [blockId, setBlockId] = useState<string | undefined>();

  // Phase 5: Tab state management
  const getTabFromUrl = (): NotesTabType => {
    const tab = searchParams.get('tab');
    if (tab && VALID_TABS.includes(tab as NotesTabType)) {
      return tab as NotesTabType;
    }
    // Legacy support: ?daily=true maps to daily tab
    if (searchParams.get('daily') === 'true') {
      return 'daily';
    }
    return 'notes'; // Default tab
  };

  const [activeTab, setActiveTab] = useState<NotesTabType>(getTabFromUrl);

  // Update tab when URL changes
  useEffect(() => {
    const newTab = getTabFromUrl();
    if (newTab !== activeTab) {
      setActiveTab(newTab);
    }
  }, [searchParams]);

  // Update URL when tab changes
  const handleTabChange = (tab: NotesTabType) => {
    setActiveTab(tab);
    navigate(`/notes?tab=${tab}`, { replace: true });
  };

  // Tag filtering state
  const [activeTags, setActiveTags] = useState<string[]>([]);
  const [showTagManager, setShowTagManager] = useState(false);

  // Template Library state
  const [showTemplateLibrary, setShowTemplateLibrary] = useState(false);
  const [showTitlePrompt, setShowTitlePrompt] = useState(false);
  const [selectedTemplate, setSelectedTemplate] = useState<NoteTemplate | null>(null);
  const [titleInput, setTitleInput] = useState('');

  // Export Modal state
  const [showExportModal, setShowExportModal] = useState(false);

  // Get store actions
  const createNote = useNotesStore((state) => state.createNote);
  const activeFolderId = useFoldersStore((state) => state.activeFolderId);

  const handleAddTag = (tag: string) => {
    if (!activeTags.includes(tag)) {
      setActiveTags([...activeTags, tag]);
    }
  };

  const handleRemoveTag = (tag: string) => {
    setActiveTags(activeTags.filter((t) => t !== tag));
  };

  const handleClearAllTags = () => {
    setActiveTags([]);
  };

  // Template selection handlers
  const handleSelectTemplate = (template: NoteTemplate) => {
    // Check if template contains {title} variable
    const variables = extractTemplateVariables(template.description);
    if (variables.includes('title')) {
      // Prompt user for title
      setSelectedTemplate(template);
      setTitleInput('');
      setShowTitlePrompt(true);
      setShowTemplateLibrary(false);
    } else {
      // Create note immediately with variable substitution
      createNoteFromTemplate(template);
    }
  };

  const createNoteFromTemplate = (template: NoteTemplate, customTitle?: string) => {
    // Substitute template variables
    const context = {
      title: customTitle,
      userName: 'User', // Could be fetched from settings in future
    };
    const processedContent = substituteTemplateVariables(template.description, context);

    // Create note with template content and tags
    const newNote = createNote({
      folderId: activeFolderId,
      title: customTitle || template.name,
      contentText: processedContent,
      tags: template.defaultTags || [],
      icon: template.icon,
    });

    log.info('Created note from template', {
      templateId: template.id,
      noteId: newNote.id,
      title: newNote.title,
    });
  };

  const handleConfirmTitle = (title: string) => {
    if (selectedTemplate && title.trim()) {
      createNoteFromTemplate(selectedTemplate, title.trim());
      setShowTitlePrompt(false);
      setSelectedTemplate(null);
      setTitleInput('');
    }
  };

  const handleCancelTitle = () => {
    setShowTitlePrompt(false);
    setSelectedTemplate(null);
    setTitleInput('');
  };

  useEffect(() => {
    document.title = 'Notes - Neuman Brain';
    log.debug('Notes page loaded');

    // Keyboard shortcut for export (Cmd/Ctrl+Shift+E)
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'E') {
        e.preventDefault();
        setShowExportModal(true);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Handle ?daily=true query parameter to open today's daily note
  useEffect(() => {
    if (searchParams.get('daily') === 'true' && dailyNotesEnabled) {
      const today = new Date();
      getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
      // Remove the query parameter after handling it
      searchParams.delete('daily');
      setSearchParams(searchParams, { replace: true });
    }
  }, [searchParams, dailyNotesEnabled, getOrCreateDailyNote, setSearchParams]);

  // Extract block ID from URL hash (#block-id)
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash && hash.startsWith('#')) {
        const id = hash.substring(1); // Remove # prefix
        setBlockId(id);
      } else {
        setBlockId(undefined);
      }
    };

    // Set initial block ID
    handleHashChange();

    // Listen for hash changes
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // Handle sidebar resize
  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsResizing(true);
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isResizing) return;
      const newWidth = Math.max(200, Math.min(500, e.clientX - 72)); // 72px is sidebar offset
      setSidebarWidth(newWidth);
    };

    const handleMouseUp = () => {
      setIsResizing(false);
    };

    if (isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'ew-resize';
      document.body.style.userSelect = 'none';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };
  }, [isResizing]);

  return (
    <PageContent page="notes">
      {/* Phase 5: Tab Navigation */}
      <TabNavigation
        tabs={NOTES_TABS}
        activeTab={activeTab}
        onTabChange={(tabId) => handleTabChange(tabId as NotesTabType)}
        ariaLabel="Notes navigation"
      />

      {/* Tab Content */}
      <div
        role="tabpanel"
        id={`tabpanel-${activeTab}`}
        aria-labelledby={`tab-${activeTab}`}
        className="min-h-[600px]"
      >
        {/* Graph Tab - Lazy loaded GraphView */}
        {activeTab === 'graph' && (
          <Suspense fallback={<GraphViewLoader />}>
            <GraphView />
          </Suspense>
        )}

        {/* Daily Notes Tab - Show Daily Notes Calendar */}
        {activeTab === 'daily' && (
          <div className="h-[calc(100vh-340px)] overflow-auto p-6">
            <DailyNotesCalendar />
          </div>
        )}

        {/* Notes Tab - Main Notes View */}
        {activeTab === 'notes' && (
          <div className="h-[calc(100vh-340px)] flex relative">
        {/* Left Sidebar - Folders + Notes List */}
        <AnimatePresence>
        {!isSidebarCollapsed && (
          <motion.div
            ref={sidebarRef}
            initial={{ width: 0, opacity: 0 }}
            animate={{ width: sidebarWidth, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col relative"
            style={{ width: sidebarWidth }}
          >
            <FolderSidebar
              activeTags={activeTags}
              onAddTag={handleAddTag}
              onRemoveTag={handleRemoveTag}
              onClearAllTags={handleClearAllTags}
              onOpenTagManager={() => setShowTagManager(true)}
            />
            <NotesList
              activeTags={activeTags}
              onOpenTemplateLibrary={() => setShowTemplateLibrary(true)}
              onOpenExportModal={() => setShowExportModal(true)}
            />

            {/* Collapse button - inside sidebar at top right */}
            <button
              onClick={() => setIsSidebarCollapsed(true)}
              className="absolute top-4 right-2 z-20 p-1.5 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-all duration-200"
              title="Collapse Sidebar"
            >
              <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 19l-7-7 7-7m8 14l-7-7 7-7" />
              </svg>
            </button>

            {/* Resize handle */}
            <div
              onMouseDown={handleMouseDown}
              className={`absolute right-0 top-0 bottom-0 w-1 cursor-ew-resize hover:bg-accent-blue/50 transition-colors ${isResizing ? 'bg-accent-blue' : ''}`}
              title="Drag to resize"
            />
          </motion.div>
        )}
      </AnimatePresence>

        {/* Sidebar expand button - shown when collapsed */}
        {isSidebarCollapsed && (
          <button
            onClick={() => setIsSidebarCollapsed(false)}
            className="flex-shrink-0 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-all duration-200 self-start mt-4 ml-2"
            title="Expand Sidebar"
          >
            <svg className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
            </svg>
          </button>
        )}

        {/* Spacer between sidebar and editor */}
        {!isSidebarCollapsed && <div className="w-4 flex-shrink-0" />}

      {/* Center - Editor */}
      <div className="flex-1 overflow-hidden flex flex-col">
        {/* Main Content Area */}
        <div className="flex-1 overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
          {activeNoteId ? (
            <NotesEditor noteId={activeNoteId} blockId={blockId} />
          ) : (
            <NotesEditorEmpty />
          )}
        </div>
      </div>

      {/* Right Sidebar - Metadata Panel (Future Feature)
          Will show: creation date, modified date, word count, tags, backlinks
          See feature_map.md Section 1.4 for planning */}
    </div>
        )}
      </div>

      {/* Tag Manager Modal */}
      <TagManager
        isOpen={showTagManager}
        onClose={() => setShowTagManager(false)}
      />

      {/* Template Library Modal */}
      <TemplateLibrary
        isOpen={showTemplateLibrary}
        onClose={() => setShowTemplateLibrary(false)}
        onSelect={handleSelectTemplate}
      />

      {/* Title Prompt Modal */}
      {showTitlePrompt && selectedTemplate && (
        <PromptDialog
          isOpen={true}
          onClose={handleCancelTitle}
          onConfirm={handleConfirmTitle}
          title="Enter Note Title"
          message={`Create a note from template "${selectedTemplate.name}". Please enter a title:`}
          defaultValue={titleInput}
          placeholder="Note title"
          confirmText="Create Note"
        />
      )}

      {/* Export Notes Modal */}
      <ExportNotesModal
        isOpen={showExportModal}
        onClose={() => setShowExportModal(false)}
      />
    </PageContent>
  );
};

