@tailwind base;
@tailwind components;
@tailwind utilities;

/* ==================== CSS DESIGN TOKENS ==================== */
/* These CSS variables power the semantic color system in Tailwind */
/* Source: src/config/theme.ts */

:root {
  /* Surface colors (backgrounds) */
  --surface-light: #FFFFFF;
  --surface-light-elevated: #F3F4F6;
  --surface-dark: #000000;
  --surface-dark-elevated: #1A1A1A;

  /* Text colors */
  --text-light-primary: #000000;
  --text-light-secondary: #6B7280;
  --text-light-tertiary: #9CA3AF;
  --text-dark-primary: #FFFFFF;
  --text-dark-secondary: #D1D5DB;
  --text-dark-tertiary: #6B7280;

  /* Border colors */
  --border-light: #E2E8F0;
  --border-dark: rgba(255, 255, 255, 0.1);

  /* Accent colors (from logo: magenta, cyan) */
  --accent-blue: #3B82F6;
  --accent-blue-hover: #2563EB;
  --accent-magenta: #E91E8C;
  --accent-magenta-hover: #D11A7C;
  --accent-cyan: #00C9FF;
  --accent-cyan-hover: #00B3E6;

  /* Extended accent colors (for status indicators, tags, features) */
  --accent-green: #10B981;
  --accent-green-hover: #059669;
  --accent-purple: #A855F7;
  --accent-purple-hover: #9333EA;
  --accent-red: #EF4444;
  --accent-red-hover: #DC2626;
  --accent-yellow: #F59E0B;
  --accent-yellow-hover: #D97706;
  --accent-orange: #F97316;
  --accent-orange-hover: #EA580C;

  /* Status colors (aliases for semantic use) */
  --status-success: #10B981;
  --status-warning: #F59E0B;
  --status-error: #EF4444;
  --status-info: #3B82F6;
}

@layer base {
  html, body {
    overflow-x: hidden; /* Prevent horizontal scrollbar at root level */
  }

  body {
    margin: 0;
    min-height: 100vh;
    font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px; /* Increased from 14px for better readability */
    line-height: 1.5; /* Professional line-height */
    @apply bg-surface-light dark:bg-surface-dark;
    @apply text-text-light-primary dark:text-text-dark-primary;
  }

  /* Professional Typography Hierarchy */
  h1 {
    font-size: 32px;
    font-weight: 700;
    line-height: 1.2;
    letter-spacing: -0.02em;
  }

  h2 {
    font-size: 24px;
    font-weight: 700;
    line-height: 1.3;
    letter-spacing: -0.01em;
  }

  h3 {
    font-size: 20px;
    font-weight: 600;
    line-height: 1.4;
  }

  h4 {
    font-size: 18px;
    font-weight: 600;
    line-height: 1.4;
  }

  h5, h6 {
    font-size: 16px;
    font-weight: 600;
    line-height: 1.5;
  }

  p {
    line-height: 1.6; /* Slightly taller for body text readability */
  }

  /* Professional emphasis weights */
  strong, b {
    font-weight: 600; /* Medium weight for emphasis */
  }

  .font-emphasis {
    font-weight: 500; /* Light emphasis */
  }

  /* Focus styles for accessibility (WCAG 2.2 compliant) */
  *:focus-visible {
    @apply outline-2 outline-accent-blue-hover;
    outline-offset: 2px;
    border-radius: 4px;
  }

  /* ==================== GLOBAL SCROLLBAR STYLING ==================== */
  /* Match Firefox's clean overlay scrollbar aesthetic across all browsers */

  /* Webkit/Chrome/Edge/Safari - Global thin scrollbars */
  * {
    scrollbar-width: thin; /* Firefox: thin scrollbar */
    scrollbar-color: rgba(128, 128, 128, 0.4) transparent; /* Firefox: thumb track colors */
  }

  *::-webkit-scrollbar {
    width: 6px; /* Vertical scrollbar width */
    height: 6px; /* Horizontal scrollbar height */
  }

  *::-webkit-scrollbar-track {
    background: transparent;
  }

  *::-webkit-scrollbar-thumb {
    background: rgba(128, 128, 128, 0.4);
    border-radius: 3px;
  }

  *::-webkit-scrollbar-thumb:hover {
    background: rgba(128, 128, 128, 0.6);
  }

  /* Dark mode scrollbar adjustments */
  .dark *::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.2);
  }

  .dark *::-webkit-scrollbar-thumb:hover {
    background: rgba(255, 255, 255, 0.35);
  }

  .dark * {
    scrollbar-color: rgba(255, 255, 255, 0.2) transparent;
  }

  /* Hide scrollbar when not needed (auto behavior) */
  *::-webkit-scrollbar-corner {
    background: transparent;
  }

  /* Mobile optimizations (Phase 6) */
  button, a, input, textarea, select {
    /* Prevent 300ms touch delay on mobile */
    touch-action: manipulation;
    /* Remove tap highlight on mobile */
    -webkit-tap-highlight-color: transparent;
  }

  /* Prevent zoom on input focus (iOS Safari) */
  input, textarea, select {
    font-size: max(16px, 1em); /* Minimum 16px to prevent zoom */
  }

  /* Dynamic viewport height for Mobile Safari (URL bar) */
  .full-height {
    height: 100dvh; /* Dynamic viewport height */
  }

  /* Wiki Link Styles - Notes backlinks and broken link detection */
  .wiki-link {
    cursor: pointer;
    text-decoration: underline;
    font-weight: 500;
  }

  .wiki-link-valid {
    @apply text-accent-cyan;
    text-decoration: underline;
    text-decoration-style: solid;
  }

  .wiki-link-valid:hover {
    @apply text-accent-cyan-hover;
  }

  .wiki-link-broken {
    @apply text-accent-red;
    text-decoration: underline;
    text-decoration-style: dashed;
  }

  .wiki-link-broken:hover {
    @apply text-accent-red-hover;
  }

  /* Hashtag Styles - Inline tagging syntax */
  .hashtag {
    cursor: pointer;
    font-weight: 500;
    @apply bg-accent-cyan/10 dark:bg-accent-cyan/20;
    @apply text-accent-cyan;
    @apply rounded px-1;
    transition: all 0.15s ease;
  }

  .hashtag:hover {
    @apply bg-accent-cyan/20 dark:bg-accent-cyan/30;
    @apply text-accent-cyan;
    transform: translateY(-1px);
  }
}

/* Scrollbar styling for sidebar */
@layer utilities {
  /* Text color utilities for accent colors */
  .text-accent-blue { color: var(--accent-blue); }
  .text-accent-blue-hover { color: var(--accent-blue-hover); }
  .text-accent-magenta { color: var(--accent-magenta); }
  .text-accent-magenta-hover { color: var(--accent-magenta-hover); }
  .text-accent-cyan { color: var(--accent-cyan); }
  .text-accent-cyan-hover { color: var(--accent-cyan-hover); }
  .text-accent-green { color: var(--accent-green); }
  .text-accent-green-hover { color: var(--accent-green-hover); }
  .text-accent-purple { color: var(--accent-purple); }
  .text-accent-purple-hover { color: var(--accent-purple-hover); }
  .text-accent-red { color: var(--accent-red); }
  .text-accent-red-hover { color: var(--accent-red-hover); }
  .text-accent-yellow { color: var(--accent-yellow); }
  .text-accent-yellow-hover { color: var(--accent-yellow-hover); }
  .text-accent-orange { color: var(--accent-orange); }
  .text-accent-orange-hover { color: var(--accent-orange-hover); }

  /* Gradient button backgrounds */
  .bg-gradient-button-primary {
    background-image: linear-gradient(to right, var(--accent-magenta), var(--accent-cyan));
  }
  .bg-gradient-button-danger {
    background-image: linear-gradient(to right, var(--accent-red), var(--accent-orange));
  }
  .bg-gradient-button-success {
    background-image: linear-gradient(to right, var(--accent-green), var(--accent-cyan));
  }

  .scrollbar-thin::-webkit-scrollbar {
    width: 6px;
  }

  .scrollbar-thin::-webkit-scrollbar-track {
    background: transparent;
  }

  .scrollbar-thin::-webkit-scrollbar-thumb {
    @apply bg-border-light;
    border-radius: 3px;
  }

  .dark .scrollbar-thin::-webkit-scrollbar-thumb {
    @apply bg-border-dark;
  }

  /* Dashboard grid layout - CSS Grid supports native column spanning */
  .dashboard-grid {
    /* Grid is defined in Dashboard.tsx using Tailwind classes:
       - Mobile: 1 column (grid-cols-1)
       - Tablet: 2 columns (md:grid-cols-2)
       - Desktop: 3 columns (lg:grid-cols-3)

       Column spanning uses Tailwind's col-span utilities:
       - 1x: (default, no class)
       - 2x: lg:col-span-2
       - 3x: lg:col-span-3 md:col-span-2
    */
  }

  /* ==================== BACKGROUND CONTRAST UTILITIES ==================== */
  /* Smart contrast detection for dashboard backgrounds */
  /* Applied to .dashboard-page to override text colors when background conflicts with theme */

  /* Dark content: Force dark text on light backgrounds (in dark mode) */
  .dark-content h1,
  .dark-content h2,
  .dark-content h3,
  .dark-content p,
  .dark-content span:not([class*="text-white"]):not([class*="bg-"]) {
    color: var(--text-light-primary) !important;
  }

  .dark-content .text-text-light-secondary,
  .dark-content .text-text-dark-secondary {
    color: var(--text-light-secondary) !important;
  }

  /* Ensure buttons and UI elements remain visible on light backgrounds */
  .dark-content .bg-surface-light-elevated {
    background-color: rgba(0, 0, 0, 0.1) !important;
  }
  .dark-content .dark\:bg-surface-dark-elevated {
    background-color: rgba(0, 0, 0, 0.15) !important;
  }

  /* Light content: Force light text on dark backgrounds (in light mode) */
  .light-content h1,
  .light-content h2,
  .light-content h3,
  .light-content p,
  .light-content span:not([class*="text-black"]):not([class*="bg-"]) {
    color: var(--text-dark-primary) !important;
  }

  .light-content .text-text-light-secondary,
  .light-content .text-text-dark-secondary {
    color: var(--text-dark-secondary) !important;
  }

  /* Ensure buttons and UI elements remain visible on dark backgrounds */
  .light-content .bg-surface-light-elevated {
    background-color: rgba(255, 255, 255, 0.15) !important;
  }
}

/* Print Styles - Calendar Print View (Quick Win #6) */
@media print {
  /* Hide all navigation, sidebars, buttons, and dashboard UI */
  header,
  nav,
  aside,
  footer,
  .sidebar,
  button.no-print,
  .no-print {
    display: none !important;
  }

  /* Force white background, black text (ignore dark mode) */
  body,
  html {
    margin: 0;
    padding: 0;
    background: white !important;
    color: black !important;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  /* Remove all dark mode colors */
  * {
    background: white !important;
    color: black !important;
    border-color: #333 !important;
  }

  /* Calendar-specific print styles */
  .calendar-container,
  [class*="calendar"] {
    width: 100% !important;
    max-width: 100% !important;
    margin: 0 !important;
    padding: 1cm !important;
    page-break-inside: avoid;
  }

  /* Calendar grid */
  table,
  [class*="grid"] {
    width: 100%;
    border-collapse: collapse;
  }

  th,
  td,
  [class*="day"],
  [class*="event"] {
    border: 1px solid #333 !important;
    padding: 0.3cm !important;
    font-size: 10pt !important;
    page-break-inside: avoid;
  }

  /* Events */
  [class*="event"],
  [class*="item"] {
    background: #f0f0f0 !important;
    border: 1px solid #666 !important;
    padding: 2mm !important;
    margin: 1mm 0 !important;
    font-size: 9pt !important;
  }

  /* Landscape orientation for better calendar fit */
  @page {
    size: landscape;
    margin: 1cm;
  }
}

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  darkMode: 'class',
  safelist: [
    // Ensure all accent color text variants are generated
    'text-accent-blue', 'text-accent-blue-hover',
    'text-accent-magenta', 'text-accent-magenta-hover',
    'text-accent-cyan', 'text-accent-cyan-hover',
    'text-accent-green', 'text-accent-green-hover',
    'text-accent-purple', 'text-accent-purple-hover',
    'text-accent-red', 'text-accent-red-hover',
    'text-accent-yellow', 'text-accent-yellow-hover',
    'text-accent-orange', 'text-accent-orange-hover',
    // Ensure gradient button backgrounds are generated
    'bg-gradient-button-primary',
    'bg-gradient-button-danger',
    'bg-gradient-button-success',
  ],
  theme: {
    extend: {
      // Custom spacing tokens for consistency across the entire application
      spacing: {
        // Widget spacing standards
        'widget-padding': '16px',       // Internal padding for all widgets (p-4 equivalent)
        'content-gap': '16px',          // Vertical spacing between content sections (space-y-4 equivalent)
        'button-gap': '8px',            // Gap between buttons in button groups (gap-2 equivalent)
        'grid-gap': '24px',             // Gap between widgets in grid layout (gap-6 equivalent)

        // Section spacing standards
        'section-margin': '24px',       // Standard section bottom margin (mb-6 equivalent)
        'section-margin-lg': '32px',    // Large section bottom margin (mb-8 equivalent)

        // Form spacing standards
        'form-field-gap': '12px',       // Gap between form fields (space-y-3 equivalent)
        'form-label-gap': '8px',        // Gap between label and input (mb-2 equivalent)
      },

      // Semantic color tokens (already defined in index.css)
      colors: {
        'surface-light': 'var(--surface-light)',
        'surface-light-elevated': 'var(--surface-light-elevated)',
        'surface-dark': 'var(--surface-dark)',
        'surface-dark-elevated': 'var(--surface-dark-elevated)',

        'text-light-primary': 'var(--text-light-primary)',
        'text-light-secondary': 'var(--text-light-secondary)',
        'text-light-tertiary': 'var(--text-light-tertiary)',
        'text-dark-primary': 'var(--text-dark-primary)',
        'text-dark-secondary': 'var(--text-dark-secondary)',
        'text-dark-tertiary': 'var(--text-dark-tertiary)',

        'border-light': 'var(--border-light)',
        'border-dark': 'var(--border-dark)',

        'accent-blue': 'var(--accent-blue)',
        'accent-blue-hover': 'var(--accent-blue-hover)',
        'accent-magenta': 'var(--accent-magenta)',
        'accent-magenta-hover': 'var(--accent-magenta-hover)',
        'accent-cyan': 'var(--accent-cyan)',
        'accent-cyan-hover': 'var(--accent-cyan-hover)',
        'accent-green': 'var(--accent-green)',
        'accent-green-hover': 'var(--accent-green-hover)',
        'accent-purple': 'var(--accent-purple)',
        'accent-purple-hover': 'var(--accent-purple-hover)',
        'accent-red': 'var(--accent-red)',
        'accent-red-hover': 'var(--accent-red-hover)',
        'accent-yellow': 'var(--accent-yellow)',
        'accent-yellow-hover': 'var(--accent-yellow-hover)',
        'accent-orange': 'var(--accent-orange)',
        'accent-orange-hover': 'var(--accent-orange-hover)',

        'status-success': 'var(--status-success)',
        'status-warning': 'var(--status-warning)',
        'status-error': 'var(--status-error)',
        'status-info': 'var(--status-info)',
      },

      // Border radius standards
      borderRadius: {
        'card': '12px',                 // Standard card border radius
        'button': '8px',                // Standard button border radius
        'input': '6px',                 // Standard input border radius
      },

      // Shadow standards
      boxShadow: {
        'modal': '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
        'card': '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
        'card-hover': '0 10px 15px -3px rgba(0, 0, 0, 0.1)',
        'glow-magenta': '0 0 20px rgba(233, 30, 140, 0.3)',
        'glow-cyan': '0 0 20px rgba(0, 201, 255, 0.3)',
        'glow-purple': '0 0 20px rgba(168, 85, 247, 0.3)',
      },

      // Background gradient utilities
      backgroundImage: {
        'gradient-button-primary': 'linear-gradient(to right, var(--accent-magenta), var(--accent-cyan))',
        'gradient-button-danger': 'linear-gradient(to right, var(--accent-red), var(--accent-orange))',
        'gradient-button-success': 'linear-gradient(to right, var(--accent-green), var(--accent-cyan))',
