   109→// Sortable Navigation Item Component
   110→interface SortableNavItemProps {
   111→  item: NavItem;
   112→  isCollapsed: boolean;
   113→  isActive: boolean;
   114→  onPageSettings: (e: React.MouseEvent, path: string) => void;
   115→  isDisablingClicks: boolean;
   116→}
   117→
   118→const SortableNavItem: React.FC<SortableNavItemProps> = ({ item, isCollapsed, isActive, onPageSettings, isDisablingClicks }) => {
   119→  const {
   120→    attributes,
   121→    listeners,
   122→    setNodeRef,
   123→    transform,
   124→    transition,
   125→    isDragging,
   126→  } = useSortable({ id: item.path });
   127→
   128→  const location = useLocation();
   129→  const { isExpanded, toggleExpanded } = useNavExpansionStore();
   130→  const hasChildren = item.children && item.children.length > 0;
   131→  const expanded = isExpanded(item.path);
   132→
   133→  const style = {
   134→    transform: CSS.Transform.toString(transform),
   135→    transition,
   136→    opacity: isDragging ? 0.5 : 1,
   137→  };
   138→
   139→  // Check if any child is active
   140→  const isChildActive = (navItem: NavItem) => {
   141→    if (!navItem.children) return false;
   142→    return navItem.children.some((child) => {
   143→      // Handle paths with query params
   144→      if (child.path.includes('?')) {
   145→        const [pathname, query] = child.path.split('?');
   146→        if (location.pathname !== pathname) return false;
   147→        const params = new URLSearchParams(query);
   148→        const currentParams = new URLSearchParams(location.search);
   149→        for (const [key, value] of params.entries()) {
   150→          if (currentParams.get(key) !== value) return false;
   151→        }
   152→        return true;
   153→      }
   154→      return location.pathname === child.path;
   155→    });
   156→  };
   157→
   158→  const childActive = isChildActive(item);
   159→
   160→  return (
   161→    <li ref={setNodeRef} style={{...style, pointerEvents: isDisablingClicks ? 'none' : 'auto'}} {...attributes}>
   162→      <Link
   163→        to={item.path}
   164→        onClick={(e) => {
   165→          if (isDisablingClicks) {
   166→            e.preventDefault();
   167→            return false;
   168→          }
   169→        }}
   170→        className={`
   171→          flex items-center gap-3 px-3 h-10 rounded-button
   172→          transition-all duration-standard ease-smooth
   173→          relative group
   174→          ${
   175→            isActive || childActive
   176→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   177→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   178→          }
   179→        `}
   180→        title={isCollapsed ? item.label : undefined}
   181→      >
   182→        {/* Active indicator (left accent) */}
   183→        {isActive && (
   184→          <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
   185→        )}
   186→
   187→        {/* Icon - Fixed 20px size - DRAG HANDLE */}
   188→        <span
   189→          {...listeners}
   190→          className="w-5 h-5 flex items-center justify-center flex-shrink-0 text-lg cursor-grab active:cursor-grabbing"
   191→          role="button"
   192→          aria-label={`Drag ${item.label} to reorder`}
   193→          tabIndex={0}
   194→        >
   195→          {item.icon}
   196→        </span>
   197→
   198→        {/* Label (hidden when collapsed) */}
   199→        {!isCollapsed && (
   200→          <>
   201→            <span className="flex-1 text-base leading-5 font-medium truncate">
   202→              {item.label}
   203→            </span>
   204→
   205→            {/* Page Settings Icon (shown on hover) */}
   206→            {item.hasSettings && (
   207→              <button
   208→                onClick={(e) => onPageSettings(e, item.path)}
   209→                className="
   210→                  opacity-0 group-hover:opacity-100
   211→                  w-5 h-5 flex items-center justify-center flex-shrink-0
   212→                  text-text-light-secondary dark:text-text-dark-secondary
   213→                  hover:text-text-light-primary dark:hover:text-text-dark-primary
   214→                  transition-opacity duration-200
   215→                "
   216→                title="Page Settings"
   217→                aria-label={`${item.label} page settings`}
   218→              >
   219→                <span className="text-sm">⚙</span>
   220→              </button>
   221→            )}
   222→
   223→            {/* Expand/Collapse Chevron (for items with children) */}
   224→            {hasChildren && (
   225→              <button
   226→                onClick={(e) => {
   227→                  e.preventDefault();
   228→                  e.stopPropagation();
   229→                  toggleExpanded(item.path);
   230→                }}
   231→                className="
   232→                  w-5 h-5 flex items-center justify-center flex-shrink-0
   233→                  text-text-light-secondary dark:text-text-dark-secondary
   234→                  hover:text-text-light-primary dark:hover:text-text-dark-primary
   235→                  transition-transform duration-200
   236→                "
   237→                title={expanded ? 'Collapse' : 'Expand'}
   238→              >
   239→                <span
   240→                  className={`text-xs transition-transform duration-200 ${
   241→                    expanded ? 'rotate-90' : ''
   242→                  }`}
   243→                >
   244→                  ▶
   245→                </span>
   246→              </button>
   247→            )}
   248→          </>
   249→        )}
   250→
   251→        {/* Tooltip for collapsed state */}
   252→        {isCollapsed && (
   253→          <div className="
   254→            absolute left-full ml-2 px-2 py-1
   255→            bg-surface-light-elevated dark:bg-surface-dark-elevated
   256→            text-text-light-primary dark:text-text-dark-primary text-xs rounded
   257→            opacity-0 group-hover:opacity-100
   258→            pointer-events-none transition-opacity duration-200
   259→            whitespace-nowrap z-50
   260→          ">
   261→            {item.label}
   262→          </div>
   263→        )}
   264→      </Link>
   265→
   266→      {/* Children (Sub-pages) - only show when expanded and not collapsed */}
   267→      {hasChildren && expanded && !isCollapsed && (
   268→        <ul className="ml-6 mt-1 space-y-1">
   269→          {item.children!.map((child) => (
   270→            <li key={child.path}>
   271→              <Link
   272→                to={child.path}
   273→                className={`
   274→                  flex items-center gap-3 px-3 h-9 rounded-button
   275→                  transition-all duration-standard ease-smooth
   276→                  relative group
   277→                  ${
   278→                    location.pathname === child.path
   279→                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
   280→                      : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   281→                  }
   282→                `}
   283→              >
   284→                {/* Active indicator (left accent) */}
   285→                {location.pathname === child.path && (
   286→                  <div className="absolute left-0 top-1.5 bottom-1.5 w-[3px] bg-accent-blue rounded-r" />
   287→                )}
   288→
   289→                {/* Icon */}
   290→                <span className="w-4 h-4 flex items-center justify-center flex-shrink-0 text-sm">
   291→                  {child.icon}
   292→                </span>
   293→
   294→                {/* Label */}
   295→                <span className="flex-1 text-sm leading-5 font-medium truncate">
   296→                  {child.label}
   297→                </span>
   298→              </Link>
   299→            </li>
   300→          ))}
   301→        </ul>
   302→      )}
   303→    </li>
   304→  );
   305→};
