   315→  const [isDisablingClicks, setIsDisablingClicks] = useState(false);
   316→  const disableTimeoutRef = useRef<NodeJS.Timeout | null>(null);
   317→  const navigate = useNavigate();
   318→  const dailyNotesEnabled = useSettingsStore((state) => state.dailyNotes.enabled);
   319→
   320→  // Check if a nav path is active (handles both pathname and query params)
   321→  const isActive = (path: string) => {
   322→    // Handle paths with query params (e.g., /schedule?tab=calendar)
   323→    if (path.includes('?')) {
   324→      const [pathname, query] = path.split('?');
   325→      if (location.pathname !== pathname) return false;
   326→      const params = new URLSearchParams(query);
   327→      const currentParams = new URLSearchParams(location.search);
   328→      // Check if all specified params match
   329→      for (const [key, value] of params.entries()) {
   330→        if (currentParams.get(key) !== value) return false;
   331→      }
   332→      return true;
   333→    }
   334→    // Simple pathname match
   335→    return location.pathname === path;
